CREATE TABLE public.accounts (
    account_id uuid NOT NULL,
    account_no character varying(20) NOT NULL,
    cif_no character varying(20) NOT NULL,
    account_type character varying(30),
    currency character varying(5) DEFAULT 'VND'::character varying,
    balance bigint,
    available_balance bigint,
    status character varying(10),
    opened_at timestamp without time zone,
    CONSTRAINT accounts_account_type_check CHECK (((account_type)::text = ANY ((ARRAY['PAYMENT'::character varying, 'SAVINGS'::character varying, 'CREDIT_CARD_SETTLEMENT'::character varying])::text[]))),
    CONSTRAINT accounts_status_check CHECK (((status)::text = ANY ((ARRAY['ACTIVE'::character varying, 'FROZEN'::character varying, 'CLOSED'::character varying])::text[])))
);


